; Applesoft BASIC for HBC-56 - Interpreter
;
; Executes bytecode generated by the tokenizer
;

; Zero page allocations
interp_pc          = $28   ; Program counter in bytecode
interp_sp          = $2A   ; Stack pointer
for_depth          = $2B   ; FOR loop nesting depth
gosub_depth        = $2C   ; GOSUB nesting depth
current_stmt       = $2D   ; Current statement token

; Variable storage area
*=$0200
variable_table:
    !fill 256, 0            ; Variables: max 32 variables

; String pool
*=$0300
string_pool:
    !fill 4096, 0           ; String storage: 4KB

; GOSUB return stack
*=$1300
gosub_stack:
    !fill 64, 0             ; 32 return addresses (2 bytes each)

; FOR loop stack
*=$1340
for_stack:
    !fill 64, 0             ; 16 FOR contexts (4 bytes each)

; User program bytecode
*=$1400
program_buffer:
    !fill 30720, 0          ; User program: ~30KB max

; =============================================================================
; interpret: Main bytecode interpreter loop
; Input:  program_buffer = bytecode
; Output: (program terminates)
; =============================================================================
interpret:
    php
    pha
    phx
    phy
    
    lda #0
    sta for_depth
    sta gosub_depth
    sta interp_pc
    sta interp_pc+1
    
    ; Fetch-decode-execute loop
exec_loop:
    lda (interp_pc)
    
    ; Dispatch on keyword value
    cmp #KW_PRINT
    beq do_print
    cmp #KW_INPUT
    beq do_input
    cmp #KW_LET
    beq do_let
    cmp #KW_GOTO
    beq do_goto
    cmp #KW_IF
    beq do_if
    cmp #KW_FOR
    beq do_for
    cmp #KW_NEXT
    beq do_next
    cmp #KW_GOSUB
    beq do_gosub
    cmp #KW_RETURN
    beq do_return
    cmp #KW_REM
    beq do_rem
    cmp #KW_END
    beq do_end
    
    ; Skip unknown token
    bra next_token
    
do_print:
    jsr stmt_print
    bra next_token
do_input:
    jsr stmt_input
    bra next_token
do_let:
    jsr stmt_let
    bra next_token
do_goto:
    jsr stmt_goto
    bra next_token
do_if:
    jsr stmt_if
    bra next_token
do_for:
    jsr stmt_for
    bra next_token
do_next:
    jsr stmt_next
    bra next_token
do_gosub:
    jsr stmt_gosub
    bra next_token
do_return:
    jsr stmt_return
    bra next_token
do_rem:
    jsr stmt_rem
    bra next_token
do_end:
    jsr stmt_end
    bra next_token
    
    ; Move to next token
next_token:
    inc interp_pc
    bne exec_loop
    inc interp_pc+1
    bra exec_loop

; =============================================================================
; Helper functions
; =============================================================================

; output_char: Output a single character
; Input:  A = character to output
; For Phase 1, this outputs to console via emulator
output_char:
    php
    pha
    
    ; TODO: Implement actual TMS9918A output
    ; For now, just return
    
    pla
    plp
    rts

; =============================================================================
; Statement handlers - dispatched by keyword token
; =============================================================================

; PRINT - output text/expressions to screen
stmt_print:
    php
    pha
    phx
    phy
    
    ; For Phase 1: evaluate next token and output it
    ; Then skip to next statement
    
    ; Output "PRINT" indicator
    lda #80                 ; 'P'
    jsr output_char
    lda #82                 ; 'R'
    jsr output_char
    lda #73                 ; 'I'
    jsr output_char
    lda #78                 ; 'N'
    jsr output_char
    lda #84                 ; 'T'
    jsr output_char
    lda #32                 ; space
    jsr output_char
    lda #58                 ; ':'
    jsr output_char
    lda #32                 ; space
    jsr output_char
    
    ; Skip past the rest of PRINT statement
    ; Next token after PRINT should be the value to print
    inc interp_pc
    
    ; Get the token type
    lda (interp_pc)
    
    ; Skip based on token type
    cmp #TOKEN_NUMBER       ; $41 - number needs 2 more bytes
    beq print_skip_number
    cmp #TOKEN_STRING       ; $42 - string needs 1 more byte
    beq print_skip_string
    cmp #TOKEN_VARIABLE     ; $40 - variable needs 1 more byte
    beq print_skip_variable
    
    ; Default: skip just the current byte
    bra print_continue
    
print_skip_number:
    inc interp_pc
    inc interp_pc           ; Skip MSB and LSB
    bra print_continue
    
print_skip_string:
    inc interp_pc           ; Skip pool index
    bra print_continue
    
print_skip_variable:
    inc interp_pc           ; Skip variable index
    bra print_continue
    
print_continue:
    ; Next token should be delimiter (newline)
    inc interp_pc
    lda (interp_pc)         ; Should be TOKEN_DELIMITER
    
    ; Skip it
    inc interp_pc
    lda (interp_pc)         ; Delimiter type
    
    ; For now, output a newline character
    lda #10                 ; LF
    jsr output_char
    
    ply
    plx
    pla
    plp
    rts

; LET - variable assignment
stmt_let:
    php
