; GOSUB - call subroutine
stmt_gosub:
    php
    pha
    phx
    phy
    
    ; GOSUB line_number
    ; For Phase 1: simplified - just skip
    ; TODO: Push return address to GOSUB stack, jump to line
    
    ply
